import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";
import type { Metadata } from "next";
import { EnterpriseCard, EnterpriseStat } from "@/components/ui/EnterpriseCard";

export const metadata: Metadata = { title: "Agenda" };

async function getAgendaData(therapistId: string) {
  const supabase = await createClient();

  const startOfWeek = new Date();
  startOfWeek.setDate(startOfWeek.getDate() - startOfWeek.getDay() + 1); // Monday
  startOfWeek.setHours(0, 0, 0, 0);

  const endOfWeek = new Date(startOfWeek);
  endOfWeek.setDate(endOfWeek.getDate() + 6);
  endOfWeek.setHours(23, 59, 59, 999);

  const [appointmentsResult, availabilityResult] = await Promise.all([
    supabase
      .from("appointments")
      .select(`
        id, scheduled_at, duration_minutes, status, type, payment_status, video_room_url,
        patient:patients(id, name, telegram_chat_id)
      `)
      .eq("therapist_id", therapistId)
      .gte("scheduled_at", startOfWeek.toISOString())
      .lte("scheduled_at", endOfWeek.toISOString())
      .not("status", "in", '("cancelled","no_show")')
      .order("scheduled_at"),

    supabase
      .from("availability")
      .select("day_of_week, start_time, end_time")
      .eq("therapist_id", therapistId),
  ]);

  return {
    appointments: appointmentsResult.data ?? [],
    availability: availabilityResult.data ?? [],
    weekStart: startOfWeek,
    weekEnd: endOfWeek,
  };
}

function statusBadge(status: string) {
  const map: Record<string, { label: string; markerClass: string; textClass: string }> = {
    confirmed: {
      label: "Confirmado",
      markerClass: "bg-[var(--color-brand)]",
      textClass: "text-[var(--color-brand)]",
    },
    pending: {
      label: "Pendente",
      markerClass: "bg-[#fbbf24]",
      textClass: "text-[#fbbf24]",
    },
    in_progress: {
      label: "Em andamento",
      markerClass: "bg-[#38bdf8]",
      textClass: "text-[#38bdf8]",
    },
    completed: {
      label: "Concluído",
      markerClass: "bg-[var(--color-text-muted)]",
      textClass: "text-[var(--color-text-muted)]",
    },
  };
  return (
    map[status] ?? {
      label: status,
      markerClass: "bg-[var(--color-text-muted)]",
      textClass: "text-[var(--color-text-muted)]",
    }
  );
}

export default async function AgendaPage() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) redirect("/auth/login");

  const { data: therapist } = await supabase
    .from("therapists")
    .select("id, name")
    .eq("user_id", user.id)
    .single();
  if (!therapist) redirect("/auth/login");

  const { appointments, weekStart, weekEnd } = await getAgendaData(therapist.id);

  const weekLabel = `${weekStart.toLocaleDateString("pt-BR", { day: "2-digit", month: "short" })} – ${weekEnd.toLocaleDateString("pt-BR", { day: "2-digit", month: "short", year: "numeric" })}`;

  // Group by day-of-week (0=Mon, 6=Sun)
  const days = ["Seg", "Ter", "Qua", "Qui", "Sex", "Sáb", "Dom"];
  const grouped: Record<number, typeof appointments> = {};
  for (let i = 0; i < 7; i++) grouped[i] = [];
  for (const appt of appointments) {
    const d = new Date(appt.scheduled_at);
    const dow = (d.getDay() + 6) % 7; // convert Sun=0 → 0=Mon
    grouped[dow].push(appt);
  }

  const confirmedCount = appointments.filter((a) => a.status === "confirmed").length;
  const pendingCount = appointments.filter((a) => a.status === "pending").length;
  const completedCount = appointments.filter((a) => a.status === "completed").length;

  return (
    <div className="w-full max-w-[1640px] mx-auto px-4 py-8 sm:px-8 lg:px-10 xl:px-12 space-y-8 animate-[fadeUp_.4s_ease-out_both]">
      {/* Header */}
      <div className="flex flex-col gap-6 lg:flex-row lg:items-end lg:justify-between">
        <div className="flex flex-col gap-1.5">
          <h1 className="font-[family-name:var(--font-display)] text-[36px] sm:text-[44px] lg:text-[52px] font-light text-[var(--color-text-primary)] tracking-tight leading-none">
            Agenda
          </h1>
          <p className="text-[15px] font-light text-[var(--color-text-secondary)] mt-1.5 capitalize">{weekLabel}</p>
        </div>
        
        {/* Weekly Controls */}
        <div className="flex flex-wrap gap-3">
          <button type="button" className="group flex items-center justify-center px-4 py-2.5 rounded-xl text-[14px] font-medium text-[var(--color-text-secondary)] bg-[var(--color-surface)] border border-[var(--color-border-subtle)] hover:border-[var(--color-border-strong)] hover:bg-[var(--color-surface-hover)] transition-all duration-300">
            <span className="mr-2 opacity-50 group-hover:opacity-100 transition-opacity">&larr;</span> Anterior
          </button>
          <button type="button" className="px-5 py-2.5 rounded-xl text-[14px] font-medium text-[var(--color-brand)] bg-[var(--color-brand)]/10 border border-[var(--color-brand)]/30 hover:bg-[var(--color-brand)]/20 hover:border-[var(--color-brand)]/50 transition-all duration-300 shadow-[0_0_15px_rgba(82,183,136,0.1)]">
            Hoje
          </button>
          <button type="button" className="group flex items-center justify-center px-4 py-2.5 rounded-xl text-[14px] font-medium text-[var(--color-text-secondary)] bg-[var(--color-surface)] border border-[var(--color-border-subtle)] hover:border-[var(--color-border-strong)] hover:bg-[var(--color-surface-hover)] transition-all duration-300">
            Próxima <span className="ml-2 opacity-50 group-hover:opacity-100 transition-opacity">&rarr;</span>
          </button>
        </div>
      </div>

      {/* Stats row */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
        <EnterpriseStat delay={0.05} label="Total esta semana" value={String(appointments.length)} />
        <EnterpriseStat delay={0.1} label="Confirmadas" value={String(confirmedCount)} />
        <EnterpriseStat delay={0.15} label="Pendentes" value={String(pendingCount)} />
        <EnterpriseStat delay={0.2} label="Concluídas" value={String(completedCount)} />
      </div>

      {/* Weekly grid container */}
      <EnterpriseCard delay={0.3} className="w-full p-5 lg:p-6 overflow-x-auto">
        <div className="grid min-w-[980px] grid-cols-7 gap-4">
          {days.map((day, i) => {
            const date = new Date(weekStart);
            date.setDate(date.getDate() + i);
            const isToday = date.toDateString() === new Date().toDateString();
            const dayAppts = grouped[i];

            return (
              <div
                key={day}
                className={`bg-[var(--color-bg-base)] rounded-2xl min-h-[470px] flex flex-col overflow-hidden transition-all duration-300 border
                  ${isToday 
                    ? "border-[var(--color-brand)]/50 shadow-[0_0_20px_rgba(82,183,136,0.15)] ring-1 ring-[var(--color-brand)]/20" 
                    : "border-[var(--color-border-subtle)] hover:border-[var(--color-border-strong)]"}`}
              >
                {/* Day header */}
                <div
                  className={`px-4 py-3.5 border-b
                  ${isToday 
                    ? "bg-[var(--color-brand)]/10 border-[var(--color-brand)]/30" 
                    : "bg-[var(--color-surface)]/50 border-[var(--color-border-subtle)]"}`}
                >
                  <div className={`text-[11px] uppercase tracking-[0.15em] font-medium mb-1
                    ${isToday ? "text-[var(--color-brand)]" : "text-[var(--color-text-muted)]"}`}>
                    {day}
                  </div>
                  <div
                    className={`font-[family-name:var(--font-display)] text-[36px] font-light leading-none
                    ${isToday ? "text-[var(--color-text-primary)]" : "text-[var(--color-text-primary)] opacity-80"}`}
                  >
                    {date.getDate()}
                  </div>
                </div>

                {/* Appointments */}
                <div className="p-3 flex-grow flex flex-col gap-2.5 overflow-y-auto custom-scrollbar">
                  {dayAppts.length === 0 ? (
                    <div className="flex items-center justify-center flex-col pt-8 opacity-20 user-select-none">
                      <span className="text-xl mb-1">☕</span>
                      <div className="text-[12px] font-medium">Livre</div>
                    </div>
                  ) : (
                    dayAppts.map((appt) => {
                      const time = new Date(appt.scheduled_at).toLocaleTimeString("pt-BR", {
                        hour: "2-digit",
                        minute: "2-digit",
                      });
                      const status = statusBadge(appt.status);
                      const patient = appt.patient as unknown as { name: string } | null;

                      return (
                        <div
                          key={appt.id}
                          className="group bg-[var(--color-surface)] hover:bg-[var(--color-surface-hover)] rounded-xl p-3 transition-all duration-300 cursor-pointer border border-[var(--color-border-subtle)] hover:border-[var(--color-border-strong)] hover:shadow-md relative overflow-hidden"
                        >
                          <div
                            className={`absolute left-0 top-0 bottom-0 w-1 opacity-80 group-hover:opacity-100 transition-opacity ${status.markerClass}`}
                          />
                          <div className="pl-1.5 flex flex-col gap-1">
                            <div className="text-[12px] font-semibold text-[var(--color-text-secondary)] tracking-wide">
                              {time}
                            </div>
                            <div className="text-[14px] text-[var(--color-text-primary)] font-medium leading-tight line-clamp-2">
                              {patient?.name ?? "Paciente Excluído"}
                            </div>
                            <div
                              className={`text-[11px] font-medium mt-0.5 inline-block opacity-80 group-hover:opacity-100 ${status.textClass}`}
                            >
                              {status.label}
                            </div>
                          </div>
                        </div>
                      );
                    })
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </EnterpriseCard>
    </div>
  );
}
